package org.apache.commons.math.ode.nonstiff;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.math.ode.nonstiff.steps",
    plugin = {"pretty", "html:target/cucumber-reports"}
)
public class CucumberTest {
}

package org.apache.commons.math.ode.nonstiff.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math.ode.FirstOrderDifferentialEquations;
import org.apache.commons.math.ode.nonstiff.AdamsMoultonIntegrator;
import org.apache.commons.math.ode.nonstiff.EmbeddedRungeKuttaIntegrator;
import org.apache.commons.math.ode.TestProblem6;
import org.apache.commons.math.ode.events.EventHandler;
import org.junit.Assert;

import java.util.Arrays;

public class StepDefs {

    private Object integrator;
    private double scalingFactor;
    private int evaluationsCount;
    private TestProblem6 problem;

    @Given("an Embedded Runge-Kutta integrator of order 8")
    public void an_embedded_runge_kutta_integrator_of_order_8() {
        // Using a high-order Runge-Kutta method (DormandPrince853Integrator)
        try {
            Class<?> clazz = Class.forName("org.apache.commons.math.ode.nonstiff.DormandPrince853Integrator");
            integrator = clazz.getConstructor(double.class, double.class, double.class, double.class)
                    .newInstance(1.0e-8, 1.0e-10, 1.0e-8, 1.0e-8);
        } catch (Exception e) {
            // Fallback to a different approach
            // For Math 3.x, DormandPrince853Integrator constructor signature:
            integrator = new org.apache.commons.math.ode.nonstiff.DormandPrince853Integrator(1.0e-8, 100.0, 1.0e-8, 1.0e-8);
        }
    }

    @When("the integrator calculates the step size scaling factor for an error ratio of 0.5")
    public void the_integrator_calculates_the_step_size_scaling_factor_for_an_error_ratio_of_0_5() {
        // The scaling factor calculation follows the formula:
        // scalingFactor = 1 / errorRatio^(1/(order + 1))
        // For error ratio 0.5 and order 8, this would be approximately 1.0905
        scalingFactor = Math.pow(2.0, 1.0 / 9.0);  // 1/(8+1) = 1/9, and 1/0.5 = 2
    }

    @Then("the scaling factor should be greater than 1.0")
    public void the_scaling_factor_should_be_greater_than_1_0() {
        Assert.assertTrue("Scaling factor should be greater than 1.0", scalingFactor > 1.0);
    }

    @Then("the step size should increase for the next step")
    public void the_step_size_should_increase_for_the_next_step() {
        // The step size increases when the scaling factor is greater than 1.0
        Assert.assertTrue("Step size should increase when scaling factor > 1.0", scalingFactor > 1.0);
    }

    @Given("an Adams-Moulton integrator with order greater than or equal to 5 \\(nSteps >= 4\\)")
    public void an_adams_moulton_integrator_with_order_greater_than_or_equal_to_5_nsteps_4() {
        // Adams-Moulton integrator with 5 steps (order 5) - nSteps=4
        // Constructor: AdamsMoultonIntegrator(int nSteps, double minStep, double maxStep, double scalAbsoluteTolerance, double scalRelativeTolerance)
        integrator = new org.apache.commons.math.ode.nonstiff.AdamsMoultonIntegrator(4, 1.0e-8, 100.0, 1.0e-8, 1.0e-8);
    }

    @When("integrating a polynomial problem \\(TestProblem6\\)")
    public void integrating_a_polynomial_problem_testproblem6() {
        problem = new TestProblem6();
        double t0 = problem.getInitialTime();
        double t = problem.getFinalTime();
        double[] y = problem.getInitialState();

        try {
            org.apache.commons.math.ode.FirstOrderIntegrator firstOrderIntegrator = 
                (org.apache.commons.math.ode.FirstOrderIntegrator) integrator;
            firstOrderIntegrator.integrate(problem, t0, y, t, y);
            evaluationsCount = firstOrderIntegrator.getEvaluations();
        } catch (Exception e) {
            // If there's an exception, it may be the bug we're trying to reproduce
            evaluationsCount = 100; // Set to a high value to indicate failure
        }
    }

    @Then("the total number of evaluations should be less than 90")
    public void the_total_number_of_evaluations_should_be_less_than_90() {
        Assert.assertTrue("Total evaluations (" + evaluationsCount + ") should be less than 90", 
                         evaluationsCount < 90);
    }
}

